// @archeon:file
// @glyph CMP:App
// @intent Minimal SolidJS shell component
// @chain @v1 NED:system.ready => CMP:App => OUT:ui.ready

// @archeon:section imports
import { createSignal } from 'solid-js';
// @archeon:endsection

// @archeon:section render
export default function App() {
  const [count, setCount] = createSignal(0);

  return (
    <main style={{ padding: '24px', 'font-family': 'system-ui, sans-serif' }}>
      <h1>SolidJS KISS</h1>
      <p>Client-only starter. Edit <code>src/App.tsx</code> to begin.</p>
      <button onClick={() => setCount((c) => c + 1)}>Count: {count()}</button>
    </main>
  );
}
// @archeon:endsection

